Here are the MSTest comparison assertions you need and a complete test class:

**Key assertions for boundary checking:**

| Assertion | Purpose |
|---|---|
| `Assert.IsGreaterThan(lower, actual)` | Value exceeds a bound |
| `Assert.IsLessThan(upper, actual)` | Value is below a bound |
| `Assert.IsInRange(actual, low, high)` | Value falls within a range |
| `Assert.ThrowsExactly<T>(...)` | Invalid input throws |

Here's a test class covering your `ScoreCalculator`:

```csharp
using Contoso.Scoring;

[TestClass]
public sealed class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calculator = new();

    // --- CalculatePercentage ---

    [TestMethod]
    [DataRow(7, 10, 70.0)]
    [DataRow(10, 10, 100.0)]
    [DataRow(0, 5, 0.0)]
    public void CalculatePercentage_ValidInputs_ReturnsExpected(
        int correct, int total, double expected)
    {
        var result = _calculator.CalculatePercentage(correct, total);
        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void CalculatePercentage_Result_IsInValidRange()
    {
        var result = _calculator.CalculatePercentage(3, 7);
        Assert.IsInRange(result, 0.0, 100.0);
        Assert.IsGreaterThan(0.0, result);  // strictly positive
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(5, 0));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(11, 10));
    }

    // --- GetGrade ---

    [TestMethod]
    [DataRow(90.0, "A")]
    [DataRow(89.9, "B")]
    [DataRow(80.0, "B")]
    [DataRow(79.9, "C")]
    [DataRow(70.0, "C")]
    [DataRow(69.9, "D")]
    [DataRow(60.0, "D")]
    [DataRow(59.9, "F")]
    [DataRow(0.0, "F")]
    [DataRow(100.0, "A")]
    public void GetGrade_AtBoundary_ReturnsCorrectGrade(
        double percentage, string expectedGrade)
    {
        Assert.AreEqual(expectedGrade, _calculator.GetGrade(percentage));
    }

    // --- NormalizeScore ---

    [TestMethod]
    public void NormalizeScore_HalfOfMax_Returns50()
    {
        var result = _calculator.NormalizeScore(50, 100);
        Assert.AreEqual(50.0, result);
    }

    [TestMethod]
    public void NormalizeScore_ExceedsMax_ClampedTo100()
    {
        var result = _calculator.NormalizeScore(150, 100);
        Assert.AreEqual(100.0, result);
        Assert.IsLessThan(101.0, result); // never exceeds 100
    }

    [TestMethod]
    public void NormalizeScore_ValidInput_IsInRange()
    {
        var result = _calculator.NormalizeScore(30, 80);
        Assert.IsInRange(result, 0.0, 100.0);
        Assert.IsGreaterThan(0.0, result);
    }

    [TestMethod]
    public void NormalizeScore_NegativeRawScore_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(-1, 100));
    }

    [TestMethod]
    public void NormalizeScore_ZeroMax_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(50, 0));
    }
}
```

**Pattern summary:**
- **`Assert.IsInRange(actual, low, high)`** — perfect for validating normalized/percentage outputs stay in `[0, 100]`
- **`Assert.IsGreaterThan(lowerBound, actual)`** — confirms a value strictly exceeds a bound
- **`Assert.IsLessThan(upperBound, actual)`** — confirms a value stays below a bound
- **`DataRow` at boundaries** (89.9, 90.0, etc.) — catches off-by-one errors in grade thresholds

These assertions require **MSTest 3.8+**. Use `MSTest.Sdk` or the `MSTest` metapackage.
